package routing

import (
	"fmt"
	"strings"

	"github.com/easel/fizeau/internal/modelcatalog"
	"github.com/easel/fizeau/internal/reasoning"
)

// Capabilities describes what a (harness, provider, model) tuple can do.
// Populated from harness config + catalog metadata + provider discovery.
type Capabilities struct {
	ContextWindow      int      // resolved tokens; 0 = unknown
	SupportsTools      bool     // supports tool/function calling
	SupportsStreaming  bool     // supports streaming responses
	SupportedReasoning []string // supported public reasoning values
	MaxReasoningTokens int      // 0 means numeric reasoning is unsupported/unknown
	SupportedPerms     []string // {"safe","supervised","unrestricted"} subset
	ExactPinSupport    bool     // accepts exact concrete model pins
	SupportedModels    []string // nil = no static allow-list
}

// HasReasoning returns true if the candidate supports the requested reasoning
// value. Empty, auto, off, and numeric 0 impose no requirement.
func (c Capabilities) HasReasoning(value string) bool {
	policy, err := reasoning.ParseString(value)
	if err != nil {
		return false
	}
	switch policy.Kind {
	case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
		return true
	case reasoning.KindTokens:
		return c.MaxReasoningTokens > 0 && policy.Tokens <= c.MaxReasoningTokens
	case reasoning.KindNamed:
		for _, supported := range c.SupportedReasoning {
			normalized, err := reasoning.Normalize(supported)
			if err == nil && normalized == policy.Value {
				return true
			}
		}
		return false
	default:
		return false
	}
}

// HasPermissions returns true if the candidate supports the requested level.
// An empty permission level always returns true.
func (c Capabilities) HasPermissions(perm string) bool {
	if perm == "" {
		return true
	}
	for _, p := range c.SupportedPerms {
		if strings.EqualFold(p, perm) {
			return true
		}
	}
	return false
}

// HasModel returns true when the exact model pin is within the static
// harness allow-list. A nil allow-list means the harness delegates validation
// to provider-side model checks.
func (c Capabilities) HasModel(model string) bool {
	if c.SupportedModels == nil || model == "" {
		return true
	}
	for _, supported := range c.SupportedModels {
		if supported == model {
			return true
		}
	}
	return false
}

// CheckGating applies all capability gates against a request and returns
// the first failure reason (free-form string for diagnostics) plus the
// typed FilterReason category for the failure. Returns ("", FilterReasonEligible)
// when all gates pass.
//
// The typed return is the authoritative classification — callers must not
// re-classify by parsing the string. The string is for human-readable
// diagnostics only.
//
// Fixes ddx-4817edfd subtree: pre-dispatch capability check covering
// context window, tool support, effort, permissions.
func CheckGating(cap Capabilities, req Request) (string, FilterReason) {
	// Context window gating: if the request declares prompt size or an effort
	// that implies a minimum context, reject candidates that can't fit.
	minCtx := req.MinContextWindow()
	if minCtx > 0 {
		if cap.ContextWindow <= 0 {
			return fmt.Sprintf("context window unknown < required %d", minCtx), FilterReasonContextTooSmall
		}
		if cap.ContextWindow < minCtx {
			return fmt.Sprintf("context window %d < required %d", cap.ContextWindow, minCtx), FilterReasonContextTooSmall
		}
	}

	// Tool-calling support gating.
	if req.RequiresTools && !cap.SupportsTools {
		return "tool calling not supported", FilterReasonNoToolSupport
	}

	if !cap.HasReasoning(req.Reasoning) {
		return fmt.Sprintf("reasoning %q not supported", req.Reasoning), FilterReasonReasoningUnsupported
	}

	// Permissions support gating.
	if !cap.HasPermissions(req.Permissions) {
		return fmt.Sprintf("permissions %q not supported", req.Permissions), FilterReasonScoredBelowTop
	}

	if req.Model != "" && !cap.HasModel(req.Model) {
		return "model not in harness allow-list", FilterReasonScoredBelowTop
	}

	// Exact-pin gating: an explicit Model field requires ExactPinSupport.
	if req.Model != "" && !cap.ExactPinSupport {
		return "exact model pin not supported", FilterReasonScoredBelowTop
	}

	return "", FilterReasonEligible
}

// CheckPowerEligibility applies catalog-power gates for unpinned automatic
// routing. Any explicit hard route pin (harness, provider, or model) bypasses
// this gate so caller-chosen routes are never broadened or overridden by
// power policy.
func CheckPowerEligibility(lookup func(string) (ModelEligibility, bool), model string, req Request) (string, FilterReason) {
	if req.Model != "" || req.Provider != "" || req.Harness != "" || lookup == nil {
		return "", FilterReasonEligible
	}
	if model == "" {
		return "model has no catalog power metadata", FilterReasonPowerMissing
	}
	eligibility, ok := lookup(model)
	if !ok {
		if req.MinPower > 0 || req.MaxPower > 0 {
			return fmt.Sprintf("model %q has no catalog power metadata", model), FilterReasonPowerMissing
		}
		return "", FilterReasonEligible
	}
	if eligibility.ExactPinOnly {
		return fmt.Sprintf("model %q is exact-pin-only", model), FilterReasonExactPinOnly
	}
	if !eligibility.AutoRoutable {
		if eligibility.Power <= 0 {
			return fmt.Sprintf("model %q has no catalog power metadata", model), FilterReasonPowerMissing
		}
		return fmt.Sprintf("model %q is not auto-routable", model), FilterReasonNotAutoRoutable
	}
	return "", FilterReasonEligible
}

// CheckProviderDefaultEligibility returns a rejection reason when the provider
// entry has ExcludeFromDefaultRouting=true and the request does not carry an
// explicit provider, harness, or exact model pin. Any explicit hard pin
// bypasses this gate so the operator can still reach opt-out providers
// intentionally.
func CheckProviderDefaultEligibility(providerName string, actualCashSpend bool, billing modelcatalog.BillingModel, excluded bool, req Request) (string, FilterReason) {
	if !excluded {
		return "", FilterReasonEligible
	}
	if req.Provider != "" || req.Harness != "" || req.Model != "" {
		return "", FilterReasonEligible
	}
	if actualCashSpend || billing == modelcatalog.BillingModelPerToken {
		return fmt.Sprintf("pay-per-token provider %s requires metered opt-in for unpinned automatic routing", providerName), FilterReasonMeteredOptInRequired
	}
	return fmt.Sprintf("provider %s excluded from default routing (include_by_default=false)", providerName), FilterReasonProviderExcludedFromDefault
}

// resolveRequestReasoning returns a copy of req with Reasoning resolved to the
// catalog's reasoning default for the request's policy/surface
// when the request asks for Reasoning=auto. This must run before CheckGating
// so candidates that only support a different reasoning level (e.g. an
// off-only variant under a policy whose surface default is "high") are
// correctly disqualified by the capability gate. Other Reasoning values
// (unset, off, named, numeric) are left untouched, preserving the existing
// behavior of those code paths.
func resolveRequestReasoning(req Request, surface string, resolver func(policy, surface string) (string, bool)) Request {
	if resolver == nil || req.Policy == "" {
		return req
	}
	policy, err := reasoning.ParseString(req.Reasoning)
	if err != nil || policy.Kind != reasoning.KindAuto {
		return req
	}
	resolved, ok := resolver(req.Policy, surface)
	if !ok || resolved == "" {
		return req
	}
	out := req
	out.Reasoning = resolved
	return out
}

	// Emit start-of-execution routing_decision so consumers know the picked
	// chain before any real work fires. The actual chain (post-fallback) is
	// stamped onto the final event's RoutingActual field.
	go s.runExecute(ctx, req, *decision, meta, inner, sessionID, overrideCtx)
	return outer, nil
}

// resolveExecuteRoute reduces the request to a concrete RouteDecision.
// The request is dispatched through the routing engine
// (internal/routing.Resolve) when under-specified (Harness == ""), or when
// Harness is set but Model is empty and routing inputs (Policy or MinPower)
// are present (engine runs within the harness's eligible models). When Harness
// is set and Model is also set, the decision is accepted verbatim.
func (s *service) resolveExecuteRoute(req ServiceExecuteRequest) (*RouteDecision, error) {
	// If Harness is omitted, route through the engine. The engine defaults to
	// local-first and auto-selects from configured endpoints when no other
	// constraints are specified — an empty request is valid if providers exist.
	if req.Harness == "" {
		return s.resolveExecuteRouteWithEngine(req)
	}
	canonical := harnesses.ResolveHarnessAlias(req.Harness)
	if !s.registry.Has(canonical) {
		return nil, fmt.Errorf("unknown harness %q", req.Harness)
	}
	cfg, _ := s.registry.Get(canonical)

	// Run per-field validators first so callers get the most specific error.
	// Empty-model routing checks run after these, right before model resolution.
	if err := validateExplicitHarnessPolicy(canonical, cfg, req.Policy); err != nil {
		return nil, err
	}
	if err := validateExplicitProvider(s.opts.ServiceConfig, cfg, req.Provider); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessModel(canonical, cfg, req.Model, req.Provider); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessReasoning(canonical, cfg, req.Reasoning); err != nil {
		return nil, err
	}
	if err := validateExplicitHarnessQuota(canonical, cfg); err != nil {
		return nil, err
	}

	// Empty-model routing: only applies to subprocess harnesses with concrete
	// model semantics. TestOnly (virtual/script), HTTP-provider (openrouter/
	// lmstudio/etc.), and "fiz" harnesses skip this block — they either use
	// DefaultModel directly or have provider-side model semantics.
	if !cfg.TestOnly && !cfg.IsHTTPProvider && canonical != "fiz" && req.Model == "" {
		if req.Policy == "" && req.MinPower == 0 {
			// Under-specified: no model, no routing inputs → silent empty model
			// avoided by failing early with a clear diagnostic.
			return nil, fmt.Errorf("under-specified routing for harness=%q: "+
				"supply --model, --policy, or --min-power", canonical)
		}
		// Policy or MinPower present: run the routing engine within the
		// harness's eligible models. Class 2 harnesses (AutoRoutingEligible=false:
		// gemini, opencode, pi) require an explicit --model.
		if !cfg.AutoRoutingEligible {
			return nil, fmt.Errorf("no auto-resolution available for harness=%q: "+
				"harness does not support auto-routing; supply an explicit --model", canonical)
		}
		return s.resolveExecuteRouteWithEngine(req)
	}

	resolvedModel := resolveSubprocessModelAlias(canonical, req.Model)
	decision := &RouteDecision{
		Harness:  canonical,
		Provider: req.Provider,
		Model:    resolvedModel,
		Reason:   "explicit",
		Power:    catalogPowerForModel(serviceRoutingCatalog(), resolvedModel),
	}
	if decision.Endpoint == "" {
		_, endpoint, _ := splitEndpointProviderRef(decision.Provider)
		decision.Endpoint = endpoint
	}
	return decision, nil
}

func validateExplicitHarnessQuota(name string, cfg harnesses.HarnessConfig) error {
	if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelSubscription {
		return nil
	}
	now := time.Now()
	qs, ok := subscriptionQuotaForHarness(name, now)
	if !ok || !qs.Present || !qs.Fresh || qs.OK {
		return nil
	}
	return explicitQuotaUnavailable(name, qs.Windows, now)
}

func explicitQuotaUnavailable(name string, windows []harnesses.QuotaWindow, now time.Time) error {
	retryAfter := earliestQuotaResetAfter(windows, now)
	if retryAfter.IsZero() {
		retryAfter = now.Add(defaultQuotaRecoveryFallbackInterval)
	}
	return &NoViableProviderForNow{
		RetryAfter:         retryAfter,
		ExhaustedProviders: []string{name},
	}
}

func earliestQuotaResetAfter(windows []harnesses.QuotaWindow, now time.Time) time.Time {
	var earliest time.Time
	for _, window := range windows {
		if window.ResetsAtUnix <= 0 {
			continue
		}
		reset := time.Unix(window.ResetsAtUnix, 0)
		if !reset.After(now) {
			continue
		}
		if earliest.IsZero() || reset.Before(earliest) {
			earliest = reset
		}
	}
	return earliest
}

func validateExplicitHarnessPolicy(name string, cfg harnesses.HarnessConfig, policy string) error {
	constraint, ok := explicitPolicyConstraint(policy)
	if !ok {
		return nil
	}
	switch constraint {
	case routing.ProviderPreferenceLocalOnly:
		if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelFixed {
			return &ErrPolicyRequirementUnsatisfied{
				Policy:       policy,
				Requirement:  constraint,
				AttemptedPin: "Harness=" + name,
			}
		}
	case routing.ProviderPreferenceSubscriptionOnly:
		if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelSubscription {
			return &ErrPolicyRequirementUnsatisfied{
				Policy:       policy,
				Requirement:  constraint,
				AttemptedPin: "Harness=" + name,
			}
		}
	}
	return nil
}

func explicitPolicyConstraint(policy string) (string, bool) {
	switch policy {
	case "air-gapped":
		return routing.ProviderPreferenceLocalOnly, true
	case "smart":
		return routing.ProviderPreferenceSubscriptionOnly, true
	default:
		return "", false
	}
}

func isExplicitPinError(err error) bool {
	var modelConstraintAmbiguous *ErrModelConstraintAmbiguous
	if errors.As(err, &modelConstraintAmbiguous) {
		return true
	}
	var modelConstraintNoMatch *ErrModelConstraintNoMatch
	if errors.As(err, &modelConstraintNoMatch) {
		return true
	}
	var modelErr *ErrHarnessModelIncompatible
	if errors.As(err, &modelErr) {
		return true
	}
	var policyErr *ErrPolicyRequirementUnsatisfied
	if errors.As(err, &policyErr) && policyErr.AttemptedPin != "" {
		return true
	}
	var pinErr *ErrUnsatisfiablePin
	if errors.As(err, &pinErr) {
		return true
	}
	var providerErr *ErrUnknownProvider
	return errors.As(err, &providerErr)
}

// validateExplicitProvider rejects pre-dispatch when the caller pinned a
// provider name that the service configuration does not recognize. Returns
// nil when no provider was pinned, when no ServiceConfig is configured (no
// provider catalog to validate against), when the provider name is known,
// or when the harness is test-only / does not consume Provider (virtual,
// script, etc. have no real provider lookup).
func validateExplicitProvider(sc ServiceConfig, cfg harnesses.HarnessConfig, provider string) error {
	if provider == "" || sc == nil {
		return nil
	}
	if cfg.TestOnly {
		return nil
	}
	lookup := provider
	if base, _, ok := splitEndpointProviderRef(provider); ok {
		lookup = base
	}
	if _, ok := sc.Provider(lookup); ok {
		return nil
	}
	known := sc.ProviderNames()
	return &ErrUnknownProvider{Provider: provider, KnownProviders: append([]string(nil), known...)}
}

func validateExplicitHarnessModel(name string, cfg harnesses.HarnessConfig, model, provider string) error {
	if model == "" || cfg.TestOnly || cfg.IsHTTPProvider || name == "fiz" {
		return nil
	}
	if modelSupportedForHarness(name, cfg, model, provider) {
		return nil
	}
	supportedModels := subprocessHarnessModelIDs(name, cfg)
	return &ErrHarnessModelIncompatible{
		Harness:         name,
		Model:           model,
		SupportedModels: append([]string(nil), supportedModels...),
	}
}

func modelSupportedForHarness(name string, cfg harnesses.HarnessConfig, model, provider string) bool {
	for _, known := range subprocessHarnessModelIDs(name, cfg) {
		if model == known {
			return true
		}
	}
	switch name {
	case "codex":
		return strings.HasPrefix(model, "gpt-")
	case "claude":
		return strings.HasPrefix(model, "claude-")
	case "pi":
		// Pi can route to non-Gemini backends (lmstudio, omlx, etc.) when a
		// provider is pinned. The pi CLI owns per-provider model validation
		// in that case, so the agent-side gate trusts the provider pin and
		// defers concrete model-ID checks to pi --list-models / pi itself.
		return provider != ""
	case "opencode":
		// OpenCode can route to configured provider/model pairs when the
		// provider is pinned; the generated opencode config and CLI own the
		// concrete model validation in that case.
		return provider != ""
	default:
		return len(cfg.Models) == 0
	}
}

func validateExplicitHarnessReasoning(name string, cfg harnesses.HarnessConfig, value Reasoning) error {
	if cfg.TestOnly {
		return nil
	}
	if len(cfg.ReasoningLevels) == 0 && cfg.MaxReasoningTokens <= 0 {
		return nil
	}
	policy, err := reasoning.ParseString(string(value))
	if err != nil {
		return fmt.Errorf("unsupported reasoning %q for harness %q: %w", value, name, err)
	}
	switch policy.Kind {
	case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:

		return baseCost * curve.LowMultiplier
	case quotaPercentUsed <= curve.MediumUntilPercent:
		return baseCost * curve.MediumMultiplier
	default:
		return baseCost * curve.HighMultiplier
	}
}

// resolveExecuteRouteWithEngine is the post-engine variant of resolveExecuteRoute.
// It is invoked by Execute when the request is under-specified
// (no PreResolved, no fully-specified Harness). Returns nil when the request
// is already specific enough that the legacy resolveExecuteRoute path applies.
func (s *service) resolveExecuteRouteWithEngine(req ServiceExecuteRequest) (*RouteDecision, error) {
	rr := RouteRequest{
		Policy:        req.Policy,
		Model:         req.Model,
		Provider:      req.Provider,
		Harness:       req.Harness,
		Reasoning:     req.Reasoning,
		Permissions:   req.Permissions,
		CachePolicy:   req.CachePolicy,
		MinPower:      req.MinPower,
		MaxPower:      req.MaxPower,
		Role:          req.Role,
		CorrelationID: req.CorrelationID,
	}
	dec, err := s.ResolveRoute(context.Background(), rr)
	if err != nil {
		if isExplicitPinError(err) {
			return nil, err
		}
		return nil, fmt.Errorf("ResolveRoute: %w", err)
	}
	return dec, nil
}

func providerPreferenceForPolicy(cat *modelcatalog.Catalog, policy string) (string, error) {
	if policy == "" {
		return routing.ProviderPreferenceLocalFirst, nil
	}
	switch policy {
	case "code-medium":
		return "", fmt.Errorf("policy %q is deprecated; use --policy default or --min-power/--max-power", policy)
	case "code-high":
		return "", fmt.Errorf("policy %q is deprecated; use --policy smart or --min-power/--max-power", policy)
	}
	if cat == nil {
		return "", &ErrUnknownPolicy{Policy: policy}
	}
	if _, _, ok := policyForName(cat, policy); !ok {
		return "", &ErrUnknownPolicy{Policy: policy}
	}
	preference := providerPreferenceForPolicyName(policy)
	switch preference {
	case routing.ProviderPreferenceLocalOnly, routing.ProviderPreferenceSubscriptionOnly,
		routing.ProviderPreferenceLocalFirst, routing.ProviderPreferenceSubscriptionFirst:
		return preference, nil
	default:
		return "", fmt.Errorf("policy %q has unsupported provider preference %q", policy, preference)
	}
}

func routePowerPolicyForRequest(cat *modelcatalog.Catalog, req RouteRequest) RoutePowerPolicy {
	policy := RoutePowerPolicy{
		PolicyName: req.Policy,
		MinPower:   req.MinPower,
		MaxPower:   req.MaxPower,
	}
	if req.Policy == "" || cat == nil {

		return &Decision{}, err
	}
	req.Policy = policyName
	if err := validateRequirements(req); err != nil {
		return &Decision{}, err
	}

	canonicalHarness := req.Harness
	if canonicalHarness == "local" {
		canonicalHarness = "fiz"
	}
	if err := explicitPinError(req, in); err != nil {
		return &Decision{}, err
	}

	var ranked []rankedCandidate
	for _, h := range in.Harnesses {
		// TestOnly harnesses (script/virtual) only reachable via explicit override.
		if h.TestOnly && canonicalHarness != h.Name {
			continue
		}
		// Automatic profile/tier routing is restricted to harnesses with full
		// coverage. Explicit Harness pins can still use experimental/ad-hoc
		// harnesses.
		if canonicalHarness == "" && !h.AutoRoutingEligible {
			continue
		}
		// Hard harness override: skip non-matching harnesses.
		if canonicalHarness != "" && canonicalHarness != h.Name {
			continue
		}
		entries := buildHarnessCandidates(h, req, in)
		ranked = append(ranked, entries...)
	}

	// Compute scores only after eligibility is final. Rejected candidates keep
	// a zero score because cost/utilization/performance/sticky ranking should
	// never influence the eligibility boundary.
	for i := range ranked {
		if !ranked[i].out.Eligible {
			continue
		}
		ranked[i].out.Score = scorePolicy(req.Policy, ranked[i].internal)
		ranked[i].out.ScoreComponents = scoreComponents(req.Policy, ranked[i].internal)
		ranked[i].out.Reason = fmt.Sprintf("policy=%s; score=%.1f", req.Policy, ranked[i].out.Score)
	}
	neutralCost, hasKnownCost := neutralKnownCost(ranked)

	// Sort: eligible first, then descending score, then cost, then locality,
	// then alphabetical.
	sort.SliceStable(ranked, func(i, j int) bool {
		ei, ej := ranked[i].out.Eligible, ranked[j].out.Eligible
		if ei != ej {
			return ei
		}
		if !ei {
			return ranked[i].out.Harness < ranked[j].out.Harness
		}
		if ranked[i].out.Score != ranked[j].out.Score {
			return ranked[i].out.Score > ranked[j].out.Score
		}
		if hasKnownCost {
			ci := candidateCostTieValue(ranked[i], neutralCost)
			cj := candidateCostTieValue(ranked[j], neutralCost)
			if ci != cj {
				return ci < cj
			}
		}
		// Locality tiebreak: prefer local cost-class.
		li := costClassRank[ranked[i].internal.CostClass] == 0
		lj := costClassRank[ranked[j].internal.CostClass] == 0
		if li != lj {
			return li
		}
		if sameLocalEndpointGroup(ranked[i].internal, ranked[j].internal) {
			if ranked[i].internal.EndpointSaturated != ranked[j].internal.EndpointSaturated {
				return !ranked[i].internal.EndpointSaturated
			}
			if ranked[i].internal.EndpointLoad != ranked[j].internal.EndpointLoad {
				return ranked[i].internal.EndpointLoad < ranked[j].internal.EndpointLoad
			}
		}
		if ranked[i].out.Harness != ranked[j].out.Harness {
			return ranked[i].out.Harness < ranked[j].out.Harness
		}
		return ranked[i].out.Provider < ranked[j].out.Provider
	})

	out := make([]Candidate, len(ranked))
	for i := range ranked {
		out[i] = ranked[i].out
	}

	for i := range out {
		if out[i].Eligible {
			return &Decision{
				Harness:        out[i].Harness,
				Provider:       out[i].Provider,
				Endpoint:       out[i].Endpoint,
				ServerInstance: out[i].ServerInstance,
				Model:          out[i].Model,
				Reason:         fmt.Sprintf("policy=%s; score=%.1f", req.Policy, out[i].Score),
				Candidates:     out,
			}, nil
		}
	}
	if quotaErr := allProvidersQuotaExhaustedError(ranked); quotaErr != nil {
		return &Decision{Candidates: out}, quotaErr
	}
	if requested := requestedModelIntent(req); requested != "" && req.Provider == "" && canonicalHarness == "" && hasLiveDiscoveryCandidates(ranked) {
		return &Decision{Candidates: out}, fmt.Errorf("no live endpoint offers a match for %s", requested)
	}
	if missingRequirement := missingPolicyRequirement(req, out); missingRequirement != "" {
		return &Decision{Candidates: out}, &ErrPolicyRequirementUnsatisfied{
			Policy:      req.Policy,
			Requirement: missingRequirement,
			Rejected:    len(out),
		}
	}
	return &Decision{Candidates: out}, noViableCandidateError(req, len(out))
}

func hasAnyEligible(ranked []rankedCandidate) bool {
	for _, rc := range ranked {
		if rc.out.Eligible {
			return true
		}
	}
	return false
}

// allProvidersQuotaExhaustedError returns ErrAllProvidersQuotaExhausted when
// at least one routing candidate was rejected solely because its provider is
// in the quota_exhausted state and no other candidate was eligible. The set
// of otherwise-eligible candidates collapses to those flagged with
// quotaExhaustedRetryAfter (the engine sets this only when the candidate
// passed every other gate). When that set is empty the existing
// no-viable / no-profile-candidate / live-discovery errors describe the
// failure more precisely.
func allProvidersQuotaExhaustedError(ranked []rankedCandidate) error {
	var exhausted []string
	seen := make(map[string]struct{})
	var earliest time.Time
	for _, c := range ranked {
		if c.quotaExhaustedRetryAfter.IsZero() {
			continue
		}
		name := c.out.Provider
		if name == "" {
			name = c.out.Harness
		}
		if _, dup := seen[name]; !dup {
			seen[name] = struct{}{}
			exhausted = append(exhausted, name)
		}
		if earliest.IsZero() || c.quotaExhaustedRetryAfter.Before(earliest) {
			earliest = c.quotaExhaustedRetryAfter
		}
	}
	if len(exhausted) == 0 {
		return nil
	}
	return &ErrAllProvidersQuotaExhausted{
		RetryAfter:         earliest,
		ExhaustedProviders: exhausted,
	}
}

func noViableCandidateError(req Request, rejected int) *NoViableCandidateError {
	return &NoViableCandidateError{
		Rejected: rejected,
		Model:    req.Model,
		Provider: req.Provider,
		Harness:  canonicalHarnessPin(req.Harness),
		MinPower: req.MinPower,
		MaxPower: req.MaxPower,
	}
}

func canonicalPolicy(policy string) (string, error) {
	if policy == "" {
		return "default", nil
	}
	switch policy {
	case "cheap", "default", "smart", "air-gapped":
		return policy, nil
	default:
		return "", &ErrUnknownPolicy{Policy: policy}
	}
}

func validateRequirements(req Request) error {
	for _, requirement := range req.Require {
		if requirement == "no_remote" {
			continue
		}
		return &ErrPolicyRequirementUnsatisfied{
			Policy:      req.Policy,
			Requirement: requirement,
		}
	}
	return nil
}

func explicitPinError(req Request, in Inputs) error {
	canonicalHarness := canonicalHarnessPin(req.Harness)
	if requirement, attemptedPin := requirementPinConflict(req, in, canonicalHarness); requirement != "" {
		return &ErrPolicyRequirementUnsatisfied{
			Policy:       req.Policy,
			Requirement:  requirement,
			AttemptedPin: attemptedPin,
		}
	}

	if canonicalHarness != "" && req.Provider != "" && !harnessCanReachProvider(in.Harnesses, canonicalHarness, req.Provider) {
		return &ErrUnsatisfiablePin{
			Pin:    "harness=" + canonicalHarness + "+provider=" + req.Provider,
			Reason: "provider is not reachable through harness",
		}
	}
	if canonicalHarness != "" && req.Model != "" {
		// Provider-routed subprocess harnesses can route any provider-pinned
		// model (lmstudio, omlx, openrouter, etc.); the harness CLI owns
		// concrete model validation in that case.
		if providerRoutedHarnessAcceptsProviderPinnedModel(canonicalHarness) && req.Provider != "" {
			return nil
		}
		h, ok := findHarness(in.Harnesses, canonicalHarness)
		if ok && h.SupportedModels != nil && !harnessSupportsModel(h.SupportedModels, req.Model) {
			return &ErrUnsatisfiablePin{
				Pin:    "harness=" + canonicalHarness + "+model=" + req.Model,
				Reason: "model is not supported by harness",
			}
		}
		if ok && h.SupportedModels == nil && !harnessCanServeExactModel(h, req.Model) {
			return &ErrUnsatisfiablePin{
				Pin:    "harness=" + canonicalHarness + "+model=" + req.Model,
				Reason: "model is not supported by harness",
			}
		}
	}
	if req.Provider != "" && req.Model != "" && !providerCanServeModel(in.Harnesses, canonicalHarness, req.Provider, req.Model) {
		return &ErrUnsatisfiablePin{
			Pin:    "provider=" + req.Provider + "+model=" + req.Model,
			Reason: "model is not available on provider",
		}
	}
	return nil
}

func providerRoutedHarnessAcceptsProviderPinnedModel(harness string) bool {
	switch harness {
	case "pi", "opencode":
		return true
	default:
		return false
	}
}

func canonicalHarnessPin(harness string) string {
	if harness == "local" {

