// NeedsLegacyPassthrough reports whether argv should bypass Cobra traversal
// until the corresponding command path has native pflag definitions.
func NeedsLegacyPassthrough(args []string) bool {
	valueFlags := map[string]bool{
		"--harness":   true,
		"--max-power": true,
		"--max-iter":  true,
		"--min-power": true,
		"--model":     true,
		"--p":         true,
		"-p":          true,
		"--policy":    true,
		"--preset":    true,
		"--provider":  true,
		"--reasoning": true,
		"--system":    true,
		"--work-dir":  true,
	}
	subcommands := map[string]bool{}
	for _, name := range mountedSubcommands() {
		subcommands[name] = true
	}
	for i := 0; i < len(args); i++ {
		arg := args[i]
		if strings.HasPrefix(arg, "-") {
			if valueFlags[arg] && i+1 < len(args) {
				i++
			}
			continue
		}
		if arg == "run" {
			return false
		}
		switch arg {
		case "log", "replay", "usage", "providers", "policies", "harnesses", "models", "check", "route-status", "corpus", "import", "update":
			return false
		case "cache":
			if i+1 < len(args) && args[i+1] == "prune" {
				return false
			}
			return true
		case "catalog":
			if i+1 < len(args) {
				switch args[i+1] {
				case "show", "models", "observations", "check", "update", "update-pricing":
					return false
				}
			}
			return true
		default:
			return subcommands[arg] || arg != ""
		}
	}
	return false
}

